// Item is a union discriminated on "type"; exactly one
// variant is set. Unknown tags are retained in Unknown (open union).
type Item struct {
	File    *FileFull
	Folder  *FolderMini
	WebLink *WebLink
	Unknown json.RawMessage
}

func (u Item) MarshalJSON() ([]byte, error) {
	switch {
	case u.File != nil:
		return json.Marshal(u.File)
	case u.Folder != nil:
		return json.Marshal(u.Folder)
	case u.WebLink != nil:
		return json.Marshal(u.WebLink)
	case u.Unknown != nil:
		return u.Unknown, nil
	}
	return []byte("null"), nil
}

func (u *Item) UnmarshalJSON(data []byte) error {
	var probe struct {
		Tag string `json:"type"`
	}
	if err := json.Unmarshal(data, &probe); err != nil {
		return err
	}
	switch probe.Tag {
	case "file":
		u.File = new(FileFull)
		return json.Unmarshal(data, u.File)
	case "folder":
		u.Folder = new(FolderMini)
		return json.Unmarshal(data, u.Folder)
	case "web_link":
		u.WebLink = new(WebLink)
		return json.Unmarshal(data, u.WebLink)
	}
	u.Unknown = append(u.Unknown[:0], data...)
	return nil
}

